const now = new Date();
// For "today" queries, use ET midnight converted to UTC
// ET is UTC-5 (EST) or UTC-4 (EDT). Use -5 as safe default.
const etOffsetMs = 5 * 3600000;
const utcNow = now.getTime();
// ET midnight today = UTC 05:00 today
const etMidnight = new Date(now.getFullYear(), now.getMonth(), now.getDate());
const todayStartUTC = new Date(etMidnight.getTime() + etOffsetMs);
// For 14d query, go 15 days back to capture UTC/ET boundary overlap
const d15 = new Date(todayStartUTC.getTime() - 15 * 86400000);
return [{ json: { todayStart: todayStartUTC.toISOString(), d14Start: d15.toISOString(), nowISO: now.toISOString() } }];

// Get tickets with configurations from Aggregate Configs
const configResult = $('Aggregate Configs').first().json;
const ticketsWithConfig = new Set(configResult.ticketsWithConfig || []);

const openTickets = $('Get Open Tickets').all();
const openedToday = $('Get Opened Today').all();
const closedToday = $('Get Closed Today').all();
const opened14d = $('Get 14d Opened').all();
const closed14d = $('Get 14d Closed').all();

const esc = (s) => (s || '').replace(/'/g, "''").replace(/\\/g, '');

function ticketToRow(t, forceClosedFlag) {
  return {
    ticket_id: t.id,
    summary: esc(t.summary),
    company_name: esc(t.company?.name),
    board_name: esc(t.board?.name),
    status_name: esc(t.status?.name),
    priority_name: esc(t.priority?.name),
    priority_id: t.priority?.id || 0,
    assigned_to: esc(t.owner?.name),
    date_entered: t._info?.dateEntered || null,
    closed_flag: forceClosedFlag !== undefined ? forceClosedFlag : (t.closedFlag || false),
    closed_date: t.closedDate || null,
    config_name: ticketsWithConfig.has(t.id) ? 'yes' : '',
    last_updated: t._info?.lastUpdated || null
  };
}

// Build rows: open tickets + opened today + closed today (dedup by ticket_id)
const seen = new Set();
const rows = [];

for (const item of openTickets) {
  if (!item.json.id) continue;
  seen.add(item.json.id);
  rows.push(ticketToRow(item.json));
}

// Add opened-today tickets not already in open list (might be already closed)
for (const item of openedToday) {
  if (!item.json.id || seen.has(item.json.id)) continue;
  seen.add(item.json.id);
  rows.push(ticketToRow(item.json));
}

// Add closed-today tickets
for (const item of closedToday) {
  if (!item.json.id || seen.has(item.json.id)) continue;
  seen.add(item.json.id);
  rows.push(ticketToRow(item.json, true));
}

// Daily counts from 14d data
const dayCounts = {};
for (const item of opened14d) {
  const de = item.json._info?.dateEntered;
  if (!de) continue;
  const dt = new Date(de);
  // EST offset: -5h (close enough, DST edge cases off by 1h)
  const etDate = new Date(dt.getTime() - 5 * 3600000);
  const d = etDate.toISOString().substring(0, 10);
  if (!dayCounts[d]) dayCounts[d] = { opened: 0, closed: 0 };
  dayCounts[d].opened++;
}
for (const item of closed14d) {
  const cd = item.json.closedDate;
  if (!cd) continue;
  const cdt = new Date(cd);
  const etCDate = new Date(cdt.getTime() - 5 * 3600000);
  const d = etCDate.toISOString().substring(0, 10);
  if (!dayCounts[d]) dayCounts[d] = { opened: 0, closed: 0 };
  dayCounts[d].closed++;
}

let sql = 'DELETE FROM dispatch_tickets;\n';

if (rows.length > 0) {
  sql += 'INSERT INTO dispatch_tickets (ticket_id, summary, company_name, board_name, status_name, priority_name, priority_id, assigned_to, date_entered, closed_flag, closed_date, config_name, last_updated) VALUES\n';
  const vr = rows.map(r => {
    const de = r.date_entered ? "'" + r.date_entered + "'" : 'NULL';
    const cd = r.closed_date ? "'" + r.closed_date + "'" : 'NULL';
    const lu = r.last_updated ? "'" + r.last_updated + "'" : 'NULL';
    return `(${r.ticket_id}, '${r.summary}', '${r.company_name}', '${r.board_name}', '${r.status_name}', '${r.priority_name}', ${r.priority_id}, '${r.assigned_to}', ${de}, ${r.closed_flag}, ${cd}, '${r.config_name}', ${lu})`;
  });
  sql += vr.join(',\n') + ';\n';
}

for (const [date, counts] of Object.entries(dayCounts)) {
  sql += `INSERT INTO dispatch_daily_counts (count_date, opened_count, closed_count) VALUES ('${date}', ${counts.opened}, ${counts.closed}) ON CONFLICT (count_date) DO UPDATE SET opened_count = EXCLUDED.opened_count, closed_count = EXCLUDED.closed_count, captured_at = NOW();\n`;
}

return [{ json: { sql, ticketCount: rows.length } }];

const items = $('Get Ticket Configs').all();
const hasConfig = new Set();
for (let i = 0; i < items.length; i++) {
  const ticketId = $('Extract IDs').all()[i]?.json?.ticketId;
  const configs = items[i].json;
  // If response is an array with items, ticket has config
  if (Array.isArray(configs) && configs.length > 0) {
    hasConfig.add(ticketId);
  } else if (configs && typeof configs === 'object' && !Array.isArray(configs)) {
    // Single config object
    if (configs.id) hasConfig.add(ticketId);
  }
}
return [{ json: { ticketsWithConfig: Array.from(hasConfig), count: hasConfig.size } }];

